import React from 'react';
import { Toolbar } from './Toolbar';
import './styles.css';

const tools = [
  { id: 'bold', label: 'Bold', icon: 'B', group: 'format' },
  { id: 'italic', label: 'Italic', icon: 'I', group: 'format' },
  { id: 'underline', label: 'Underline', icon: 'U', group: 'format' },
  { id: 'strikethrough', label: 'Strikethrough', icon: 'S', group: 'format', disabled: true },
  { id: 'align-left', label: 'Align Left', icon: '⫷', group: 'align' },
  { id: 'align-center', label: 'Align Center', icon: '⫶', group: 'align' },
  { id: 'align-right', label: 'Align Right', icon: '⫸', group: 'align' },
  { id: 'link', label: 'Insert Link', icon: '🔗', group: 'insert' },
  { id: 'image', label: 'Insert Image', icon: '🖼', group: 'insert' },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Accessible Toolbar</h1>
      <Toolbar tools={tools} />
    </div>
  );
}

import React, { useState, useRef, useCallback } from 'react';
import './styles.css';

export interface Tool {
  id: string;
  label: string;
  icon: string;
  group: string;
  disabled?: boolean;
}

interface ToolbarProps {
  tools: Tool[];
}

// TODO: Implement accessible toolbar with roving tabindex
// 1. role='toolbar', aria-label on container
// 2. Only one button has tabIndex={0}
// 3. Arrow keys move focus, skip disabled
// 4. Home/End keys
// 5. Wrap around
// 6. Visual group dividers

export const Toolbar: React.FC<ToolbarProps> = ({ tools }) => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [output, setOutput] = useState('No action');
  // TODO: refs for buttons

  const handleActivate = (tool: Tool) => {
    if (tool.disabled) return;
    setOutput(`Activated: ${tool.label}`);
  };

  // Group tools for visual dividers
  const groups: Tool[][] = [];
  let currentGroup: Tool[] = [];
  tools.forEach((tool, i) => {
    if (i > 0 && tool.group !== tools[i - 1].group) {
      groups.push(currentGroup);
      currentGroup = [];
    }
    currentGroup.push(tool);
  });
  if (currentGroup.length) groups.push(currentGroup);

  return (
    <div>
      <div className="toolbar">
        {/* TODO: Add role, aria-label, keyboard handler */}
        {groups.map((group, gi) => (
          <React.Fragment key={gi}>
            {gi > 0 && <div className="toolbar__divider" role="separator" />}
            {group.map(tool => {
              const flatIndex = tools.indexOf(tool);
              return (
                <button
                  key={tool.id}
                  data-testid={`tool-${tool.id}`}
                  className={`toolbar__btn${flatIndex === activeIndex ? ' toolbar__btn--active' : ''}${tool.disabled ? ' toolbar__btn--disabled' : ''}`}
                  onClick={() => handleActivate(tool)}
                  // TODO: tabIndex, aria-disabled, aria-describedby
                >
                  <span className="toolbar__icon">{tool.icon}</span>
                </button>
              );
            })}
          </React.Fragment>
        ))}
      </div>
      <p data-testid="output" className="toolbar__output">{output}</p>
    </div>
  );
};

.toolbar {
  display: inline-flex;
  align-items: center;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  padding: 0.25rem;
  background: #f9fafb;
  gap: 0.125rem;
}

.toolbar__btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 2rem;
  height: 2rem;
  border: none;
  border-radius: 0.25rem;
  background: transparent;
  cursor: pointer;
  font-size: 0.875rem;
  font-weight: 600;
  color: #374151;
  position: relative;
}

.toolbar__btn:hover:not(.toolbar__btn--disabled) {
  background: #e5e7eb;
}

.toolbar__btn:focus-visible {
  outline: 2px solid #3b82f6;
  outline-offset: 1px;
}

.toolbar__btn--active {
  background: #dbeafe;
  color: #1d4ed8;
}

.toolbar__btn--disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.toolbar__icon {
  font-size: 0.9375rem;
}

.toolbar__divider {
  width: 1px;
  height: 1.5rem;
  background: #d1d5db;
  margin: 0 0.25rem;
}

.toolbar__output {
  margin-top: 1rem;
  padding: 0.75rem;
  background: #f3f4f6;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  color: #374151;
}

.toolbar__tooltip {
  position: absolute;
  bottom: calc(100% + 0.5rem);
  left: 50%;
  transform: translateX(-50%);
  padding: 0.25rem 0.5rem;
  background: #1f2937;
  color: white;
  font-size: 0.75rem;
  font-weight: 400;
  border-radius: 0.25rem;
  white-space: nowrap;
  pointer-events: none;
}

