import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Roving Tabindex Toolbar', () => {
  it('toolbar has role=toolbar', () => {
    render(<App />);
    expect(screen.getByTestId('toolbar')).toHaveAttribute('role', 'toolbar');
  });

  it('only first non-disabled button has tabIndex=0', () => {
    render(<App />);
    const bold = screen.getByTestId('tool-bold');
    const italic = screen.getByTestId('tool-italic');
    expect(bold.tabIndex).toBe(0);
    expect(italic.tabIndex).toBe(-1);
  });

  it('arrow right moves focus to next button', () => {
    render(<App />);
    const toolbar = screen.getByTestId('toolbar');
    const bold = screen.getByTestId('tool-bold');
    bold.focus();
    fireEvent.keyDown(toolbar, { key: 'ArrowRight' });
    expect(document.activeElement).toBe(screen.getByTestId('tool-italic'));
  });

  it('skips disabled button', () => {
    render(<App />);
    const toolbar = screen.getByTestId('toolbar');
    const underline = screen.getByTestId('tool-underline');
    underline.focus();
    fireEvent.keyDown(toolbar, { key: 'ArrowRight' });
    // Should skip strikethrough (disabled) and land on align-left
    expect(document.activeElement).toBe(screen.getByTestId('tool-align-left'));
  });

  it('wraps around from last to first', () => {
    render(<App />);
    const toolbar = screen.getByTestId('toolbar');
    const image = screen.getByTestId('tool-image');
    image.focus();
    fireEvent.keyDown(toolbar, { key: 'ArrowRight' });
    expect(document.activeElement).toBe(screen.getByTestId('tool-bold'));
  });

  it('Home key focuses first button', () => {
    render(<App />);
    const toolbar = screen.getByTestId('toolbar');
    const center = screen.getByTestId('tool-align-center');
    center.focus();
    fireEvent.keyDown(toolbar, { key: 'Home' });
    expect(document.activeElement).toBe(screen.getByTestId('tool-bold'));
  });

  it('End key focuses last button', () => {
    render(<App />);
    const toolbar = screen.getByTestId('toolbar');
    const bold = screen.getByTestId('tool-bold');
    bold.focus();
    fireEvent.keyDown(toolbar, { key: 'End' });
    expect(document.activeElement).toBe(screen.getByTestId('tool-image'));
  });

  it('clicking a button activates it', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('tool-bold'));
    expect(screen.getByTestId('output')).toHaveTextContent('Bold');
  });

  it('disabled button has aria-disabled', () => {
    render(<App />);
    expect(screen.getByTestId('tool-strikethrough')).toHaveAttribute('aria-disabled', 'true');
  });
});

