import React, { useState, useRef, useCallback } from 'react';
import './styles.css';

export interface Tool {
  id: string;
  label: string;
  icon: string;
  group: string;
  disabled?: boolean;
}

interface ToolbarProps {
  tools: Tool[];
}

export const Toolbar: React.FC<ToolbarProps> = ({ tools }) => {
  const [activeIndex, setActiveIndex] = useState(() => tools.findIndex(t => !t.disabled));
  const [output, setOutput] = useState('No action');
  const btnRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const handleActivate = (tool: Tool) => {
    if (tool.disabled) return;
    setOutput(`Activated: ${tool.label}`);
  };

  const findNext = (from: number, direction: 1 | -1): number => {
    let idx = from;
    for (let i = 0; i < tools.length; i++) {
      idx = (idx + direction + tools.length) % tools.length;
      if (!tools[idx].disabled) return idx;
    }
    return from;
  };

  const findFirst = () => tools.findIndex(t => !t.disabled);
  const findLast = () => {
    for (let i = tools.length - 1; i >= 0; i--) {
      if (!tools[i].disabled) return i;
    }
    return 0;
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    let nextIndex = activeIndex;
    switch (e.key) {
      case 'ArrowRight':
        e.preventDefault();
        nextIndex = findNext(activeIndex, 1);
        break;
      case 'ArrowLeft':
        e.preventDefault();
        nextIndex = findNext(activeIndex, -1);
        break;
      case 'Home':
        e.preventDefault();
        nextIndex = findFirst();
        break;
      case 'End':
        e.preventDefault();
        nextIndex = findLast();
        break;
      default:
        return;
    }
    setActiveIndex(nextIndex);
    btnRefs.current[nextIndex]?.focus();
  };

  const groups: Tool[][] = [];
  let currentGroup: Tool[] = [];
  tools.forEach((tool, i) => {
    if (i > 0 && tool.group !== tools[i - 1].group) {
      groups.push(currentGroup);
      currentGroup = [];
    }
    currentGroup.push(tool);
  });
  if (currentGroup.length) groups.push(currentGroup);

  return (
    <div>
      <div
        data-testid="toolbar"
        className="toolbar"
        role="toolbar"
        aria-label="Text formatting"
        onKeyDown={handleKeyDown}
      >
        {groups.map((group, gi) => (
          <React.Fragment key={gi}>
            {gi > 0 && <div className="toolbar__divider" role="separator" />}
            {group.map(tool => {
              const flatIndex = tools.indexOf(tool);
              return (
                <button
                  key={tool.id}
                  ref={el => { btnRefs.current[flatIndex] = el; }}
                  data-testid={`tool-${tool.id}`}
                  className={`toolbar__btn${flatIndex === activeIndex ? ' toolbar__btn--active' : ''}${tool.disabled ? ' toolbar__btn--disabled' : ''}`}
                  tabIndex={flatIndex === activeIndex ? 0 : -1}
                  aria-disabled={tool.disabled || undefined}
                  aria-label={tool.label}
                  onClick={() => {
                    if (!tool.disabled) {
                      setActiveIndex(flatIndex);
                      handleActivate(tool);
                    }
                  }}
                >
                  <span className="toolbar__icon">{tool.icon}</span>
                </button>
              );
            })}
          </React.Fragment>
        ))}
      </div>
      <p data-testid="output" className="toolbar__output">{output}</p>
    </div>
  );
};
